    $this->SetTextColor(3,3,3);  // Establece el color del texto (en este caso es blanco)
    $this->Cell(59,3.5,'PROPINA SUGER. ('.number_format($reg[0]["propinasugerida"], 2, '.', ',').'%): '.$simbolo.number_format($reg[0]["totalpropina"], 2, '.', ','),1,0,'L');

