    if($_SESSION['acceso'] == "administradorG" && !empty($reg)){

    $this->Ln();
    $this->Cell(335,6,"Nｺ ".utf8_decode($reg[0]['documento'])." SUCURSAL: ".utf8_decode($reg[0]["cuitsucursal"]),0,0,'L');
